class Solution {
public:
    int findNthDigit(int n) {
        long long numDigits = 1, count = 9;
        long long start = 1;
        long long total = 0;
        while (total + count * numDigits < n) {
            total += count * numDigits;
            numDigits++;
            count *= 10;
            start *= 10;
        }
        start += (n - total) / numDigits;
        return (n - total) % numDigits;
    }
};
```

